I encountered a similar problem using vgetty after upgrading from
FreeBSD i386 7.3 to 8.1.

Upon code inspection it appears that the uart driver (which replaces
the sio driver used in FreeBSD 7.3) fails to check that CTS is asserted
prior to transmitting characters.

The enclosed lightly tested patch seems to resolve the problem.

-- John
------------------------8<------------------------------8<---------------
--- dev/uart/uart_tty.c.ORIGINAL	2010-06-13 22:09:06.000000000 -0400
+++ dev/uart/uart_tty.c	2010-07-16 02:08:36.000000000 -0400
@@ -169,6 +169,11 @@ uart_tty_outwakeup(struct tty *tp)
 	if (sc->sc_txbusy)
 		return;

+	if ((tp->t_termios.c_cflag & CCTS_OFLOW)
+	    && ! sc->sc_hwoflow
+	    && ! (sc->sc_hwsig & SER_CTS))
+		return;
+
 	sc->sc_txdatasz = ttydisc_getc(tp, sc->sc_txbuf, sc->sc_txfifosz);
 	if (sc->sc_txdatasz != 0)
 		UART_TRANSMIT(sc);
@@ -316,11 +321,8 @@ uart_tty_intr(void *arg)
 		sig = pend & SER_INT_SIGMASK;
 		if (sig & SER_DDCD)
 			ttydisc_modem(tp, sig & SER_DCD);
-		if ((sig & SER_DCTS) && (tp->t_termios.c_cflag & CCTS_OFLOW) &&
-		    !sc->sc_hwoflow) {
-			if (sig & SER_CTS)
-				uart_tty_outwakeup(tp);
-		}
+		if (sig & SER_DCTS)
+			uart_tty_outwakeup(tp);
 	}

 	if (pend & SER_INT_TXIDLE)
